// Utility to extract and send game data to Captivate from ProducerDashboard

export function sendRoundDataToCaptivate(roundData) {
  console.log('window.serviceHandler:', window.serviceHandler);
  console.log('typeof scheduleVariablesEx:', typeof window.serviceHandler?.scheduleVariablesEx);
  const card1 = roundData.C1 || {};
  const card2 = roundData.C2 || {};

  const data = {
    card1_aura: card1.Aura ?? 0,
    card1_skill: card1.Skill ?? 0,
    card1_stamina: card1.Stamina ?? 0,
    card1_character: card1.character ?? "",
    card1_rarity: card1.rarity ?? "",
    card1_score: card1.Score ?? 0,
    card1_color: card1.color ?? "",
    card1_imageUrl: card1.card ?? "",
    card1_rarityImageUrl: card1.rarityImage ?? "",
    card1_tier: card1.tier ?? "",
    card1_quote: card1.quote ?? "",
    card1_vfc: card1.vfc ?? "",
    card1_cardId: card1.card ?? "",
    card2_aura: card2.Aura ?? 0,
    card2_skill: card2.Skill ?? 0,
    card2_stamina: card2.Stamina ?? 0,
    card2_character: card2.character ?? "",
    card2_rarity: card2.rarity ?? "",
    card2_score: card2.Score ?? 0,
    card2_color: card2.color ?? "",
    card2_imageUrl: card2.card ?? "",
    card2_rarityImageUrl: card2.rarityImage ?? "",
    card2_tier: card2.tier ?? "",
    card2_quote: card2.quote ?? "",
    card2_vfc: card2.vfc ?? "",
    card2_cardId: card2.card ?? "",
  };

  // Captivate ServiceHandler pattern (no connect, no constructor)
  if (
    window.serviceHandler &&
    typeof window.serviceHandler.scheduleVariablesEx === 'function'
  ) {
    window.serviceHandler.scheduleVariablesEx(data);
    console.log('Sent data to Captivate via ServiceHandler:', data);
  } else {
    console.warn('Captivate ServiceHandler not available. Data not sent:', data);
  }
}
